def stringIndices(wordsContainer: list, wordsQuery: list) -> list:
    answer_array = []
    for suffix in wordsQuery:
        biggest_suffix_found = 0
        smallest_word_size = -1
        smallest_word_index = 0
        for index,word in enumerate(wordsContainer):
            for i in range(len(suffix)-1,-2 + biggest_suffix_found,-1):
                s = suffix[-(i+1):]
                if len(s) > len(word):
                    continue
                if s == word[-(i+1):]:
                    if len(word) < smallest_word_size or smallest_word_size == -1 or len(s) > biggest_suffix_found:
                        biggest_suffix_found = len(s)
                        smallest_word_size = len(word)
                        smallest_word_index = index
                    break
        if biggest_suffix_found > 0:
            answer_array.append(smallest_word_index)
        else:
            answer_array.append(wordsContainer.index(min(wordsContainer, key=len)))
    return answer_array

